#include<stdio.h>
#include<stdlib.h>
int cmpfun(const void * a, const void * b)
{
   return ( *(int*)a - *(int*)b );
}
int main()
{
    int a,ac,b,bc,cc,c,n,i,days=0,day,j,d[3];
    scanf("%d %d %d",&a,&b,&c);
    d[0]=a/3;
    d[1]=b/2;
    d[2]=c/2;
    qsort(d,3,sizeof(int),cmpfun);

    day=d[0]*7;
    a-=(d[0]*3);
    b-=(d[0]*2);
    c-=(d[0]*2);

    for(j=1;j<8;j++)
    {
        n=0;
        ac=a;
        bc=b;
        cc=c;
        i=j;
        while(1)
        {

            if(i==1||i==4||i==7)
            {
                if(ac==0)break;
                ac--;
            }
            else if(i==2||i==6)
            {
                if(bc==0)break;
                bc--;
            }
            else
            {
                if(cc==0)break;
                cc--;
            }
            if(i==7)i=1;
            else i++;
            n++;
            //printf("%d %d %d\n",ac,bc,cc);
        }
        if(days<n)days=n;
    }
    printf("%d",days+day);
}

